UPDATE STOCMASK
   SET MOD_DATE = SYSDATE
     , MOD_USER_ID = #{ses.userId}
     , MASK_APPROVAL = #{MASK_APPROVAL}
     , MASK_APPROVAL_USER_ID = #{ses.userId}
	 , MASK_APPROVAL_RETURN = #{MASK_APPROVAL_RETURN}
 WHERE GATE_CD = #{ses.gateCd}
   AND MASK_SQ = #{MASK_SQ}
   AND ACCESS_DATE = #{ACCESS_DATE}
   AND USER_ID = #{USER_ID}
